112â†’export function usePosStore() {
113â†’  const [loadState, setLoadState] = useState<LoadState>("booting");
114â†’  const [error, setError] = useState("");
115â†’  const [products, setProducts] = useState<Product[]>([]);
116â†’  const [categories, setCategories] = useState<Category[]>([]);
117â†’  const [customers, setCustomers] = useState<Customer[]>([]);
118â†’  const [users, setUsers] = useState<User[]>([]);
119â†’  const [settings, setSettings] = useState<Settings | null>(null);
120â†’  const [transactions, setTransactions] = useState<Transaction[]>([]);
121â†’  const [heldOrders, setHeldOrders] = useState<HeldOrder[]>([]);
122â†’  const [syncQueue, setSyncQueue] = useState<SyncQueueItem[]>([]);
123â†’  const [cart, setCart] = useState<CartItem[]>([]);
124â†’  const [discount, setDiscount] = useState(0);
125â†’  const [remarks, setRemarks] = useState("");
126â†’  const [customerId, setCustomerId] = useState("walk-in");
127â†’  const [scPwdDraft, setScPwdDraft] = useState<ScPwdCustomerDetails | null>(null);
128â†’  const [activeScPwdDiscount, setActiveScPwdDiscount] = useState(false);
129â†’  const [scPwdTransactionLog, setScPwdTransactionLog] = useState<ScPwdTransactionLogRow[]>([]);
130â†’  const [scPwdAlerts, setScPwdAlerts] = useState<ScPwdAlert[]>([]);
131â†’  const [currentUser, setCurrentUser] = useState<User | null>(null);
132â†’  const [forcedOffline, setForcedOffline] = useState(false);
133â†’  const [browserOnline, setBrowserOnline] = useState(true);
134â†’  const [lastReceipt, setLastReceipt] = useState<Transaction | null>(null);
135â†’  const [printFailure, setPrintFailure] = useState<{ transaction: Transaction; printer: PrinterProfile | null; queueJobId?: string } | null>(null);
136â†’  const [syncing, setSyncing] = useState(false);
137â†’  const [syncStrategy, setSyncStrategy] = useState<ConflictResolutionStrategy>("lww");
138â†’  const [lastSyncReport, setLastSyncReport] = useState<{
139â†’    processed: number;
140â†’    synced: number;
141â†’    conflicts: number;
142â†’    failures: number;
143â†’    retries: number;
144â†’  } | null>(null);
145â†’  const [conflictItems, setConflictItems] = useState<SyncQueueItem[]>([]);
146â†’  const [featureFlags, setFeatureFlags] = useState<FeatureFlags>(DEFAULT_FEATURE_FLAGS);
147â†’  const [storagePersistence, setStoragePersistence] = useState<StoragePersistenceStatus>("unknown");
148â†’  const [telemetryEvents, setTelemetryEvents] = useState<TelemetryEvent[]>([]);
149â†’  const [offlineStartedAt, setOfflineStartedAt] = useState<string | null>(null);
150â†’  const [offlineSecondsTotal, setOfflineSecondsTotal] = useState(0);
151â†’  const [rxPrescriptionDrafts, setRxPrescriptionDrafts] = useState<PrescriptionDraft[]>([]);
152â†’  const [rxRedFlags, setRxRedFlags] = useState<RxRedFlag[]>([
153â†’    {
154â†’      id: "rx-flag-1",
155â†’      severity: "warning",
156â†’      title: "Duplicate DD dispensing window",
157â†’      reason: "Same patient received Diazepam 5mg within 30 days.",
158â†’      createdAt: new Date().toISOString()
159â†’    }
160â†’  ]);
161â†’  const [rxRefusals, setRxRefusals] = useState<PrescriptionRefusal[]>([]);
162â†’  const [rxSettings, setRxSettings] = useState<RxSettings>({
163â†’    ddEddLowStockThreshold: 10,
164â†’    profileRetentionYears: 10,
165â†’    hardBlockPrototypeReset: true
166â†’  });
167â†’
168â†’  const online = browserOnline && !forcedOffline;
169â†’  const pendingSync = useMemo(() => syncQueue.filter((item) => item.status === "pending"), [syncQueue]);
170â†’
171â†’  // Derive pharmacists from real users instead of hardcoded mock data
172â†’  const rxPharmacists = useMemo<RxPharmacist[]>(() => {
173â†’    return users
174â†’      .filter((u) => u.role === "pharmacist" || u.role === "admin")
175â†’      .map((u): RxPharmacist => ({
176â†’        id: u.id,
177â†’        name: u.fullname,
178â†’        prcNumber: u.prcNumber || "N/A",
179â†’        role: u.role === "pharmacist" ? "pharmacist" : "admin",
180â†’      }));
181â†’  }, [users]);
182â†’
183â†’  const recordEvent = useCallback((event: Omit<TelemetryEvent, "ts">) => {
184â†’    const eventWithTs: TelemetryEvent = { ...event, ts: new Date().toISOString() };
185â†’    setTelemetryEvents((existing) => [...existing.slice(-399), eventWithTs]);
186â†’  }, []);
187â†’
188â†’  const withNextVersion = useCallback(<T extends { version?: number }>(entity: T): T & { version: number } => {
189â†’    return {
190â†’      ...entity,
191â†’      version: (entity.version ?? 0) + 1,
192â†’    };
193â†’  }, []);
194â†’
195â†’  const refresh = useCallback(async () => {
196â†’    const [nextProducts, nextCategories, nextCustomers, nextUsers, nextSettings, nextTransactions, nextHeld, nextSync, nextFlags, nextConflicts] =
197â†’      await Promise.all([
198â†’        getAll("products"),
199â†’        getAll("categories"),
200â†’        getAll("customers"),
201â†’        getAll("users"),
202â†’        getOne("settings", "store"),
203â†’        getAll("transactions"),
204â†’        getAll("heldOrders"),
205â†’        getAll("syncQueue"),
206â†’        getFeatureFlags(),
207â†’        getConflictItems()
208â†’      ]);
209â†’
210â†’    setProducts(nextProducts);
211â†’    setCategories(nextCategories);
212â†’    setCustomers(nextCustomers.map((customer: Customer) => ({ ...customer, createdAt: customer.createdAt ?? new Date(0).toISOString() })));
213â†’    setUsers(nextUsers);
214â†’    setSettings(nextSettings || null);
215â†’    setTransactions(nextTransactions.sort((a: Transaction, b: Transaction) => b.createdAt.localeCompare(a.createdAt)));
216â†’    setHeldOrders(nextHeld.sort((a: HeldOrder, b: HeldOrder) => b.createdAt.localeCompare(a.createdAt)));
217â†’    setSyncQueue(nextSync.sort((a: SyncQueueItem, b: SyncQueueItem) => b.createdAt.localeCompare(a.createdAt)));
218â†’    setFeatureFlags(nextFlags);
219â†’    setConflictItems(nextConflicts);
220â†’  }, []);
221â†’
222â†’  useEffect(() => {
223â†’    let mounted = true;
224â†’
225â†’    async function boot() {
226â†’      try {
227â†’        setBrowserOnline(typeof navigator === "undefined" ? true : navigator.onLine);
228â†’        await seedIfNeeded();
229â†’        await refresh();
230â†’        const persistence = await requestPersistentStorage();
231â†’        if (mounted) {
232â†’          setStoragePersistence(persistence);
233â†’          recordEvent({ type: "storage_persistence", details: { status: persistence } });
234â†’          logStructured("info", "storage.persistence", { status: persistence });
235â†’        }
236â†’        if (mounted) {
237â†’          const existingSession = readSession();
238â†’          let nextUser: User | null = null;
239â†’
240â†’          if (existingSession) {
241â†’            const sessionUser = await getOne("users", existingSession.userId);
242â†’            if (sessionUser && sessionUser.username === existingSession.username) {
243â†’              nextUser = sessionUser;
244â†’            }
245â†’          }
246â†’
247â†’          if (!nextUser && shouldAutoLogin()) {
248â†’            const result = await loginLocal("admin", "admin");
249â†’            nextUser = result.auth && result.user ? result.user : null;
250â†’          }
251â†’
252â†’          setCurrentUser(nextUser);
253â†’          setLoadState("ready");
254â†’        }
255â†’      } catch (bootError) {
256â†’        if (mounted) {
257â†’          setError(bootError instanceof Error ? bootError.message : "Unable to open local database.");
258â†’          setLoadState("error");
259â†’        }
260â†’      }
261â†’    }
262â†’
263â†’    boot();
264â†’
265â†’    const onOnline = () => setBrowserOnline(true);
266â†’    const onOffline = () => setBrowserOnline(false);
267â†’
268â†’    if (typeof window !== "undefined") {
269â†’      window.addEventListener("online", onOnline);
270â†’      window.addEventListener("offline", onOffline);
271â†’    }
272â†’
273â†’    return () => {
274â†’      if (typeof window !== "undefined") {
275â†’        window.removeEventListener("online", onOnline);
276â†’        window.removeEventListener("offline", onOffline);
277â†’      }
278â†’    };
279â†’  }, [refresh]);
280â†’
281â†’  useEffect(() => {
282â†’    recordEvent({ type: "network_state", details: { online } });
283â†’    logStructured("info", "network.state", { online, forcedOffline, browserOnline });
284â†’    if (online) {
285â†’      if (offlineStartedAt) {
286â†’        const durationSeconds = (Date.now() - new Date(offlineStartedAt).getTime()) / 1000;
287â†’        setOfflineSecondsTotal((value) => value + Math.max(0, durationSeconds));
288â†’        setOfflineStartedAt(null);
289â†’      }
290â†’      return;
291â†’    }
292â†’
293â†’    if (!offlineStartedAt) {
294â†’      setOfflineStartedAt(new Date().toISOString());
295â†’    }
296â†’  }, [browserOnline, forcedOffline, offlineStartedAt, online, recordEvent]);
297â†’
298â†’  const totals = useMemo(() => {
299â†’    const scPwdSettings = settings?.scPwdSettings;
300â†’    if (activeScPwdDiscount && scPwdSettings?.enabled) {
301â†’      const scPwdTotals = calculateScPwdTotals(cart, products, settings!, discount, scPwdSettings);
302â†’      const processedCart = buildScPwdCartItems(cart, products, settings!, scPwdSettings, discount);
303â†’      return calculateCartTotals(
304â†’        processedCart,
305â†’        settings || { chargeTax: false, vatPercentage: 0 },
306â†’        scPwdTotals.manualDiscount
307â†’      );
308â†’    }
309â†’    return calculateCartTotals(cart, settings || { chargeTax: false, vatPercentage: 0 }, discount);
310â†’  }, [cart, discount, settings, activeScPwdDiscount, products]);
311â†’
312â†’  const addToCart = useCallback((product: Product) => {
313â†’    if (product.tracksStock && product.quantity <= 0) return;
314â†’
315â†’    // Prescription / controlled product role check
316â†’    const isControlled =
317â†’      product.drugClassification === "DD, Rx" ||
318â†’      product.drugClassification === "EDD, Rx" ||
319â†’      product.drugClassification === "Rx" ||
320â†’      product.drugClassification === "Pharmacist-Only OTC" ||
321â†’      product.isPrescription ||
322â†’      product.behindCounter;
323â†’
324â†’    if (isControlled && currentUser?.role !== "pharmacist" && currentUser?.role !== "admin") {
325â†’      return;
326â†’    }
327â†’
328â†’    setCart((items) => {
329â†’      const existing = items.find((item) => item.productId === product.id);
330â†’      if (existing) {
331â†’        return items.map((item) =>
332â†’          item.productId === product.id
333â†’            ? {
334â†’                ...item,
335â†’                quantity: product.tracksStock ? Math.min(item.quantity + 1, product.quantity) : item.quantity + 1
336â†’              }
337â†’            : item
338â†’        );
339â†’      }
340â†’
341â†’      return [
342â†’        ...items,
343â†’        { productId: product.id, productName: product.name, price: product.price, quantity: 1 }
344â†’      ];
345â†’    });
346â†’  }, [currentUser]);
347â†’
348â†’  const updateCartQuantity = useCallback((productId: string, quantity: number) => {
349â†’    const product = products.find((item) => item.id === productId);
350â†’    const max = product?.tracksStock ? product.quantity : 999;
351â†’    const safeQuantity = Math.max(1, Math.min(quantity, max || 1));
352â†’    setCart((items) => items.map((item) => (item.productId === productId ? { ...item, quantity: safeQuantity } : item)));
353â†’  }, [products]);
354â†’
355â†’  const removeFromCart = useCallback((productId: string) => {
356â†’    setCart((items) => items.filter((item) => item.productId !== productId));
357â†’  }, []);
358â†’
359â†’  const clearCart = useCallback(() => {
360â†’    setCart([]);
361â†’    setDiscount(0);
362â†’    setRemarks("");
363â†’    setCustomerId("walk-in");
364â†’    setScPwdDraft(null);
365â†’    setActiveScPwdDiscount(false);
366â†’  }, []);
367â†’
368â†’  const completeSale = useCallback(
369â†’    async (input: SaleInput) => {
370â†’      if (!settings || !currentUser || cart.length === 0) return null;
371â†’      if (!featureFlags.payments) return null;
372â†’      return traced("pos.complete_sale", { paymentMethod: input.method, cartLines: cart.length }, async () => {
373â†’        // Load BIR settings for OR series
374â†’        const birRaw = await getOne("birSettings", "bir");
375â†’        const bir = birRaw as BirSettings | undefined;
376â†’        if (bir && bir.currentOrNumber >= bir.orSeriesEnd) {
377â†’          throw new Error("OR series exhausted. Please contact BIR for a new PTU.");
378â†’        }
379â†’        const scPwdSettings = settings.scPwdSettings;
380â†’        const isScPwdActive = activeScPwdDiscount && scPwdSettings?.enabled;
381â†’        const processedCart = isScPwdActive
382â†’          ? buildScPwdCartItems(cart, products, settings, scPwdSettings, discount)
383â†’          : cart;
384â†’        const saleTotals = calculateCartTotals(
385â†’          processedCart,
386â†’          settings,
387â†’          isScPwdActive ? 0 : discount
388â†’        );
389â†’        const paid = input.method === "cash" ? input.paid : saleTotals.total;
390â†’
391â†’        // Assign OR number from BIR settings or fallback to local number
392â†’        const orNumber = bir ? String(bir.currentOrNumber) : makeLocalNumber();
393â†’
394â†’        const transaction: Transaction = {
395â†’          id: crypto.randomUUID(),
396â†’          version: 1,
397â†’          localNumber: orNumber,
398â†’          items: processedCart.map((item) => ({ ...item, lineTotal: money(item.price * item.quantity) })),
399â†’          customerId,
400â†’          cashierId: currentUser.id,
401â†’          createdAt: new Date().toISOString(),
402â†’          subtotal: saleTotals.subtotal,
403â†’          discount: saleTotals.discount,
404â†’          tax: saleTotals.tax,
405â†’          total: saleTotals.total,
406â†’          paid,
407â†’          change: calculateChange(saleTotals.total, paid),
408â†’          paymentMethod: input.method,
409â†’          paymentStatus: input.paymentStatus,
410â†’          paymentReference: sanitizeString(input.reference),
411â†’          syncStatus: "pending",
412â†’          remarks: sanitizeString(remarks),
413â†’          scPwdMetadata: isScPwdActive && scPwdDraft
414â†’            ? {
415â†’                ...scPwdDraft,
416â†’                scPwdDiscountAmount: saleTotals.discount,
417â†’                scPwdVatRemoved: 0
418â†’              }
419â†’            : undefined
420â†’        };
421â†’
422â†’        // Build SC/PWD log row (but don't commit to state yet)
423â†’        let scPwdRow: ScPwdTransactionLogRow | null = null;
424â†’        if (isScPwdActive && scPwdDraft) {
425â†’          scPwdRow = {
426â†’            id: crypto.randomUUID(),
427â†’            transactionId: transaction.id,
428â†’            orNumber: transaction.localNumber,
429â†’            timestamp: transaction.createdAt,
430â†’            discountType: scPwdDraft.chosenDiscount ?? scPwdDraft.discountType,
431â†’            customerName: scPwdDraft.fullName,
432â†’            idNumber: scPwdDraft.idNumber,
433â†’            grossAmount: saleTotals.subtotal,
434â†’            scPwdDiscountAmount: saleTotals.discount,
435â†’            vatRemoved: transaction.scPwdMetadata?.scPwdVatRemoved ?? 0,
436â†’            netAmount: saleTotals.total,
437â†’            items: processedCart
438â†’              .filter((i) => i.scPwdDiscounted)
439â†’              .map((i) => ({
440â†’                name: i.productName,
441â†’                qty: i.quantity,
442â†’                originalPrice: i.originalPrice ?? i.price,
443â†’                discountAmount: i.scPwdDiscountAmount ?? 0,
444â†’                finalPrice: i.price
445â†’              })),
446â†’            proxyPurchase: scPwdDraft.proxyPurchase,
447â†’            supervisorOverride: transaction.scPwdMetadata?.supervisorOverride
448â†’          };
449â†’        }
450â†’
451â†’        const updatedProducts = decrementStock(products, processedCart).map((product) => withNextVersion(product));
452â†’        const updatedBir: (BirSettings & { id: string }) | null = bir
453â†’          ? { ...bir, id: "bir", currentOrNumber: bir.currentOrNumber + 1 }
454â†’          : null;
455â†’
456â†’        // Atomic write: all succeed or all fail together
457â†’        await atomicSaleWrite(updatedProducts, transaction, updatedBir);
458â†’
459â†’        // Side effects only after atomic write succeeds
460â†’        recordEvent({ type: "payment_attempt", details: { status: input.paymentStatus, method: input.method, total: saleTotals.total } });
461â†’        if (scPwdRow) {
462â†’          setScPwdTransactionLog((prev) => [...prev, scPwdRow!]);
463â†’        }
464â†’
465â†’        await enqueueSync({ entity: "transaction", operation: "create", payload: transaction });
466â†’        await enqueueSync({ entity: "product", operation: "update", payload: updatedProducts });
467â†’        recordEvent({ type: "sync_enqueued", details: { entity: "transaction", localNumber: transaction.localNumber } });
468â†’        recordEvent({ type: "order_completed", details: { localNumber: transaction.localNumber, total: transaction.total } });
469â†’        logStructured("info", "order.completed", {
470â†’          localNumber: transaction.localNumber,
471â†’          method: input.method,
472â†’          status: input.paymentStatus,
473â†’          total: transaction.total
474â†’        });
475â†’
476â†’        // Attempt thermal print
477â†’        try {
478â†’          const {
479â†’            PrinterService,
480â†’            buildReceipt,
481â†’            createPrinterBackend,
482â†’            enqueuePrintJob,
483â†’            getReceiptLayoutOptions,
484â†’            resolvePrinterForRole
485â†’          } = await import("./printer");
486â†’          const profiles = await getAll("printerProfiles");
487â†’          const orPrinter = resolvePrinterForRole(profiles, "or");
488â†’          if (orPrinter) {
489â†’            const commands = buildReceipt("normal", orPrinter, bir, transaction, getReceiptLayoutOptions(orPrinter));
490â†’            const service = new PrinterService(createPrinterBackend);
491â†’            const connectResult = await service.connect(orPrinter);
492â†’            if (connectResult.status === "success") {
493â†’              const printResult = await service.print(commands);
494â†’              await service.disconnect();
495â†’              if (printResult.status !== "success") {
496â†’                const queuedJob = await enqueuePrintJob(Number(transaction.localNumber), transaction.id, "normal", commands, orPrinter.id);
497â†’                setPrintFailure({ transaction, printer: orPrinter, queueJobId: queuedJob.id });
498â†’              } else {
499â†’                // log success printer activity handled by pos-prototype if needed
500â†’              }
501â†’            } else {
502â†’              const queuedJob = await enqueuePrintJob(Number(transaction.localNumber), transaction.id, "normal", commands, orPrinter.id);
503â†’              setPrintFailure({ transaction, printer: orPrinter, queueJobId: queuedJob.id });
504â†’            }
505â†’          }
